arguments.new_str:
using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup and register a pooled prediction engine
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var allData = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');
var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2);

// Map "Yes"/"No" to boolean Label using serializable ValueMapping
var labelMap = new[]
{
    new KeyValuePair<ReadOnlyMemory<char>, bool>("Yes".AsMemory(), true),
    new KeyValuePair<ReadOnlyMemory<char>, bool>("No".AsMemory(), false),
};

var pipeline = mlContext.Transforms.Conversion.MapValue("Label", labelMap, "Churned")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "PurchaseHistory", "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(split.TrainSet);

// Evaluate and log metrics
var predictions = model.Transform(split.TestSet);
try
{
    var metrics = mlContext.BinaryClassification.Evaluate(predictions);
    Console.WriteLine($"AUC: {metrics.AreaUnderRocCurve:F4}");
    Console.WriteLine($"F1:  {metrics.F1Score:F4}");
    Console.WriteLine($"Accuracy: {metrics.Accuracy:F4}");
}
catch (ArgumentOutOfRangeException)
{
    Console.WriteLine("Warning: Test set too small to compute all metrics. Add more data for reliable evaluation.");
}

// Save model and register PredictionEnginePool
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerData customer) =>
{
    var prediction = pool.Predict(customer);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedChurned,
        prediction.Probability,
        prediction.Score
    });
});

app.Run();

